{
  "name": "AuditFlow AI",
  "description": "Une interface professionnelle d'audit de site web alimentée par Gemini. Saisissez des scores, obtenez des analyses en temps réel et générez des rapports complets."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Category {
  DESIGN = 'Design & UX',
  CONTENT = 'Contenu & Structure',
  PERFORMANCE = 'Performance & Tech',
  SEO = 'SEO & Visibilité',
  ACCESSIBILITY = 'Accessibilité'
}

export interface EvaluationItem {
  id: string;
  category: Category;
  score: number; // 0 to 100
  notes: string;
}

export interface SiteMetadata {
  url: string;
  summary: string;
  techStack: string[];
  initialImpressions: string[];
}

export interface AuditState {
  items: EvaluationItem[];
  metadata: SiteMetadata | null;
  overallScore: number;
}

export interface GeminiReport {
  executiveSummary: string;
  strengths: string[];
  weaknesses: string[];
  recommendations: string[];
  finalVerdict: string;
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { AuditState, Category, GeminiReport } from "../types";

// Initialize Gemini Client
// CRITICAL: process.env.API_KEY is handled externally.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Scans a URL using Google Search Grounding to provide initial context.
 */
export const scanWebsiteUrl = async (url: string): Promise<{ summary: string; techStack: string[]; initialImpressions: string[] }> => {
  try {
    const modelId = 'gemini-3-flash-preview'; 

    const prompt = `
      Analyse le site web suivant : ${url}.
      Utilise Google Search pour trouver des informations récentes sur ce site.

      Renvoie une réponse au format JSON strict avec les champs suivants :
      - summary: Un résumé professionnel de 2 phrases sur ce que fait le site.
      - techStack: Une liste estimée des technologies utilisées (ex: React, WordPress, Shopify, etc.) ou "Inconnu".
      - initialImpressions: 3 points clés notables (positifs ou neutres) sur la réputation ou l'apparence publique du site.
    `;

    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            techStack: { type: Type.ARRAY, items: { type: Type.STRING } },
            initialImpressions: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["summary", "techStack", "initialImpressions"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("Aucune réponse de l'IA");

    return JSON.parse(text);

  } catch (error) {
    console.error("Erreur lors du scan:", error);
    throw error;
  }
};

/**
 * Generates a full audit report based on the filled form data.
 */
export const generateAuditReport = async (auditData: AuditState): Promise<GeminiReport> => {
  try {
    const modelId = 'gemini-3-flash-preview';

    // Construct a structured prompt with the user's manual evaluation data
    const evaluationContext = auditData.items.map(item => 
      `- ${item.category}: Score ${item.score}/100. Notes: "${item.notes || 'Aucune note'}"`
    ).join('\n');

    const prompt = `
      Agis comme un Expert Senior en Audit Web et Qualité Digitale.
      Rédige un rapport d'audit pour le site : ${auditData.metadata?.url || 'URL non spécifiée'}.

      Voici les données brutes de l'évaluation manuelle effectuée par l'auditeur :
      ${evaluationContext}

      Le résumé du site est : ${auditData.metadata?.summary || 'N/A'}.

      Génère un rapport professionnel, constructif et détaillé en JSON.
    `;

    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            executiveSummary: { type: Type.STRING, description: "Résumé exécutif du rapport" },
            strengths: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Liste des points forts" },
            weaknesses: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Liste des points faibles" },
            recommendations: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Actions recommandées prioritaires" },
            finalVerdict: { type: Type.STRING, description: "Conclusion finale courte" }
          },
          required: ["executiveSummary", "strengths", "weaknesses", "recommendations", "finalVerdict"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("Aucune réponse de rapport");

    return JSON.parse(text);

  } catch (error) {
    console.error("Erreur génération rapport:", error);
    throw error;
  }
};

import React, { memo } from 'react';
import { EvaluationItem } from '../types';
import { MessageSquare } from 'lucide-react';

interface CriteriaRowProps {
  item: EvaluationItem;
  onChange: (id: string, field: keyof EvaluationItem, value: any) => void;
}

const CriteriaRow: React.FC<CriteriaRowProps> = memo(({ item, onChange }) => {

  const getScoreColor = (score: number) => {
    if (score >= 80) return 'text-green-400';
    if (score >= 50) return 'text-yellow-400';
    return 'text-red-400';
  };

  const getBarColor = (score: number) => {
    if (score >= 80) return 'bg-green-500';
    if (score >= 50) return 'bg-yellow-500';
    return 'bg-red-500';
  };

  return (
    <div className="bg-slate-800/50 rounded-xl p-5 border border-slate-700/50 hover:border-slate-600 transition-all duration-300">
      <div className="flex flex-col md:flex-row gap-6 items-start md:items-center justify-between mb-4">
        <div className="flex-1">
          <h3 className="text-sm font-semibold text-slate-300 uppercase tracking-wider mb-1">
            {item.category}
          </h3>
          <div className="flex items-center gap-3">
             <span className={`text-3xl font-bold font-mono ${getScoreColor(item.score)}`}>
               {item.score}
             </span>
             <span className="text-xs text-slate-500 font-medium">/ 100</span>
          </div>
        </div>

        <div className="flex-1 w-full md:w-auto min-w-[200px]">
          <input
            type="range"
            min="0"
            max="100"
            value={item.score}
            onChange={(e) => onChange(item.id, 'score', parseInt(e.target.value))}
            className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
          />
          <div className="w-full bg-slate-700 h-1.5 rounded-full mt-2 overflow-hidden">
            <div 
                className={`h-full ${getBarColor(item.score)} transition-all duration-500 ease-out`} 
                style={{ width: `${item.score}%` }}
            />
          </div>
        </div>
      </div>

      <div className="relative group">
        <div className="absolute top-3 left-3 text-slate-500 group-focus-within:text-blue-400 transition-colors">
          <MessageSquare size={16} />
        </div>
        <textarea
          value={item.notes}
          onChange={(e) => onChange(item.id, 'notes', e.target.value)}
          placeholder="Observations, détails techniques, bugs rencontrés..."
          className="w-full bg-slate-900/50 border border-slate-700 text-slate-300 text-sm rounded-lg py-2.5 pl-9 pr-4 focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500/50 outline-none transition-all placeholder:text-slate-600 min-h-[80px]"
        />
      </div>
    </div>
  );
});

export default CriteriaRow;

import React from 'react';
